/**
 * restart-subscription.js  —  Netlify Function
 * ─────────────────────────────────────────────────────────────────────────────
 * Restarts a FoxyCart subscription by calling FoxyCart's cart endpoint
 * server-side with the subscription's sub_token. Clears sub_enddate and
 * sets sub_nextdate to tomorrow.
 *
 * No FoxyCart API credentials required — the sub_token already proves
 * authorization (it's an HMAC generated by FoxyCart).
 *
 * Called by the "Restart Subscription" button on the checkout/cart cancel page.
 *
 * DEPLOYMENT
 * ──────────
 *  1. Copy this file to your Netlify project:
 *       netlify/functions/restart-subscription.js
 *
 *  2. Deploy (git push or Netlify CLI).
 *
 *  3. In the checkout + cart templates, set GD_RESTART_FN to:
 *       https://YOUR-SITE.netlify.app/.netlify/functions/restart-subscription
 *
 * No environment variables required.
 * ─────────────────────────────────────────────────────────────────────────────
 */

'use strict';

const https = require('https');

/* ─── CORS ──────────────────────────────────────────────────────────────────── */

const CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

/* ─── HTTPS HELPER ──────────────────────────────────────────────────────────── */

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const req = https.request(
      { hostname: u.hostname, port: 443, path: u.pathname + u.search, method: 'GET' },
      (res) => {
        // Drain the body so the socket is released
        res.on('data', () => {});
        res.on('end', () => resolve({ status: res.statusCode, location: res.headers.location || '' }));
      }
    );
    req.on('error', reject);
    req.end();
  });
}

/* ─── HANDLER ───────────────────────────────────────────────────────────────── */

exports.handler = async (event) => {
  // CORS preflight
  if (event.httpMethod === 'OPTIONS') {
    return { statusCode: 200, headers: CORS, body: '' };
  }

  if (event.httpMethod !== 'POST') {
    return { statusCode: 405, headers: CORS, body: 'Method Not Allowed' };
  }

  let sub_token, fcsid, timestamp, sub_nextdate, store_domain;
  try {
    ({ sub_token, fcsid, timestamp, sub_nextdate, store_domain } = JSON.parse(event.body || '{}'));
  } catch (_) {
    return { statusCode: 400, headers: { ...CORS, 'Content-Type': 'application/json' }, body: JSON.stringify({ error: 'Invalid JSON body' }) };
  }

  if (!sub_nextdate || !store_domain || (!sub_token && !fcsid)) {
    return { statusCode: 400, headers: { ...CORS, 'Content-Type': 'application/json' }, body: JSON.stringify({ error: 'Missing sub_nextdate, store_domain, and either sub_token or fcsid' }) };
  }

  // Only allow calls to FoxyCart domains — prevents SSRF
  if (!store_domain.endsWith('.foxycart.com') && store_domain !== 'foxycart.com') {
    return { statusCode: 400, headers: { ...CORS, 'Content-Type': 'application/json' }, body: JSON.stringify({ error: 'Invalid store_domain' }) };
  }

  try {
    // Build FoxyCart cart update URL.
    // sub_enddate=0000-00-00 means "no end date" (clears pending cancellation).
    // We have two ways to identify the session:
    //   sub_token — available on the cart cancel page (/cart?sub_token=...)
    //   fcsid     — available on the checkout cancel page (/checkout?fcsid=...)
    const params = new URLSearchParams({ sub_enddate: '0000-00-00', sub_nextdate });
    if (sub_token) {
      params.set('sub_token', sub_token);
      if (timestamp) params.set('timestamp', timestamp);
    } else {
      params.set('fcsid', fcsid);
    }

    const cartUrl = `https://${store_domain}/cart?${params.toString()}`;
    console.log('[restart-subscription] Calling:', cartUrl);

    const res = await httpsGet(cartUrl);
    console.log('[restart-subscription] Response status:', res.status, '| Location:', res.location);

    // FoxyCart returns 302 redirect to /checkout after a successful update.
    // 200 is also a success (some configurations return the cart page directly).
    if (res.status === 302 || res.status === 301 || res.status === 200) {
      return {
        statusCode: 200,
        headers: { ...CORS, 'Content-Type': 'application/json' },
        body: JSON.stringify({ success: true }),
      };
    }

    throw new Error(`FoxyCart returned unexpected status ${res.status}`);

  } catch (err) {
    console.error('[restart-subscription]', err.message);
    return {
      statusCode: 500,
      headers: { ...CORS, 'Content-Type': 'application/json' },
      body: JSON.stringify({ error: err.message }),
    };
  }
};
